WITH row_rank_1 AS (
    SELECT rr.LINK_EMP_ORG_PK, rr.EMPLOYEE_PK, rr.ORGANIZATION_PK, rr.LOAD_DATE, rr.RECORD_SOURCE,
           ROW_NUMBER() OVER(
               PARTITION BY rr.LINK_EMP_ORG_PK
               ORDER BY rr.LOAD_DATE
           ) AS row_number
    FROM S45969_DBT_DB.S45969_DBT_AH_SCHEMA.v_stg_employee_organization AS rr
    WHERE rr.LINK_EMP_ORG_PK IS NOT NULL
    AND rr.EMPLOYEE_PK IS NOT NULL
    AND rr.ORGANIZATION_PK IS NOT NULL
    QUALIFY row_number = 1
),

records_to_insert AS (
    SELECT a.LINK_EMP_ORG_PK, a.EMPLOYEE_PK, a.ORGANIZATION_PK, a.LOAD_DATE, a.RECORD_SOURCE
    FROM row_rank_1 AS a
    LEFT JOIN S45969_DBT_DB.S45969_DBT_AH_SCHEMA.link_emp_org AS d
    ON a.LINK_EMP_ORG_PK = d.LINK_EMP_ORG_PK
    WHERE d.LINK_EMP_ORG_PK IS NULL
)

SELECT * FROM records_to_insert